from dataclasses import dataclass, field, asdict
import json

@dataclass
class ResearchEnvelope:
    """Standard envelope for research outputs."""
    agent_id: str
    question: str
    findings: list[str]
    confidence: float
    gaps: list[str]
    metadata: dict = field(default_factory=dict)

    def to_json(self) -> str:
        return json.dumps(asdict(self), indent=2)

    @classmethod
    def from_json(cls, text: str) -> "ResearchEnvelope":
        data = json.loads(text)
        return cls(**data)

    def validate(self) -> list[str]:
        """Returns a list of validation errors. Empty = valid."""
        errors = []
        if not self.question:
            errors.append("question is required")
        if not isinstance(self.findings, list):
            errors.append("findings must be a list")
        if not (0.0 <= self.confidence <= 1.0):
            errors.append(f"confidence {self.confidence} out of range [0, 1]")
        return errors

# Agent that produces a structured envelope:
def structured_researcher(question: str, agent_id: str = "researcher-1") -> ResearchEnvelope:
    import anthropic
    client = anthropic.Anthropic()
    resp = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=512,
        system=(
            "Answer the question with factual information. "
            'Return ONLY a JSON object: {"question": "...", "findings": [...], "confidence": 0.0-1.0, "gaps": [...]}'
        ),
        messages=[{"role": "user", "content": question}],
    )
    text = resp.content[0].text.strip()
    if text.startswith("```"):
        lines = text.split("\n")
        text = "\n".join(lines[1:-1] if lines[-1].strip() == "```" else lines[1:])
    try:
        data = json.loads(text)
    except json.JSONDecodeError:
        data = {"question": question, "findings": [text], "confidence": 0.5, "gaps": []}
    return ResearchEnvelope(agent_id=agent_id, **data)

# Agent that consumes the envelope and validates before using:
def envelope_critic(envelope: ResearchEnvelope) -> dict:
    errors = envelope.validate()
    if errors:
        return {"approved": False, "reason": f"Invalid envelope: {errors}"}
    if envelope.confidence < 0.7:
        return {"approved": False, "reason": f"Confidence {envelope.confidence} too low"}
    if envelope.gaps:
        return {"approved": False, "reason": f"Unresolved gaps: {envelope.gaps}"}
    return {"approved": True, "reason": "Envelope valid and complete"}

# Pipeline:
envelope = structured_researcher("What is the melting point of iron?")
verdict = envelope_critic(envelope)
print(verdict)
# {"approved": True, "reason": "Envelope valid and complete"}
